#include <condition_variable>
#include <mutex>
#include <queue>
#include <thread>
#include <iostream>

std::mutex mtx;
std::condition_variable cv;
std::queue<int> tasks;
bool done = false;

// المستهلك: ينتظر حتى يوجد عنصر أو ينتهي الإنتاج
void consumer() {
    std::unique_lock<std::mutex> lock(mtx);
    while (!done || !tasks.empty()) {
        // wait مع lambda: يتحقق من الشرط، إن كان خاطئًا يُحرر القفل وينام
        // عند الإيقاظ يُعاود أخذ القفل ويتحقق مجددًا
        cv.wait(lock, [&] { return !tasks.empty() || done; });

        if (!tasks.empty()) {
            int job = tasks.front();
            tasks.pop();
            lock.unlock(); // حرر القفل أثناء المعالجة
            std::cout << "معالجة: " << job << '\n';
            lock.lock(); // أعد القفل للدورة التالية
        }
    }
}

// المنتج: يُضيف عناصر ويُنبّه المستهلك
void producer() {
    for (int i = 1; i <= 5; ++i) {
        {
            std::lock_guard<std::mutex> lock(mtx);
            tasks.push(i);
        }
        cv.notify_one(); // يُوقظ خيطًا واحدًا ينتظر
    }
    {
        std::lock_guard<std::mutex> lock(mtx);
        done = true;
    }
    cv.notify_all(); // يُوقظ كل الخيوط لتفحص done
}

